checker_dsl:
EXISTS (`method M`) {
  AND {
    (`M is declared in a class C`),
    (`C has simple name "RandomUtil"`),
    (`M has name matching pattern "generate%"`),
    (`M has return type String`),
    EXISTS (`return statement RS`) {
      AND {
        (`RS is contained in the body of M`),
        (`RS is the only statement in a singleton block that forms the body of M`),
        EXISTS (`method call MC`) {
          AND {
            (`MC is the expression returned by RS`),
            EXISTS (`method RM`) {
              AND {
                (`RM is the method called by MC`),
                (`RM is declared in a class AC`),
                OR {
                  (`AC has qualified name "org.apache.commons.lang.RandomStringUtils"`),
                  (`AC has qualified name "org.apache.commons.lang3.RandomStringUtils"`)
                },
                NOT { (`RM has name "random"`) }
              }
            }
          }
        }
      }
    }
  }
}
